<?php require_once dirname(__DIR__) . '/includes/auth.php'; require_admin(); $rows=db()->query('SELECT sub.*,seq.name sequence_name FROM subscribers sub JOIN email_sequences seq ON seq.id=sub.sequence_id ORDER BY sub.id DESC LIMIT 250')->fetchAll(); include '_header.php'; ?>
<h1>Subscribers</h1><table><tr><th>Name</th><th>Email</th><th>Sequence</th><th>Status</th><th>Signup</th><th>IP</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['name'])?></td><td><?=e($r['email'])?></td><td><?=e($r['sequence_name'])?></td><td><?=e($r['status'])?></td><td><?=e($r['signup_date'])?></td><td><?=e($r['signup_ip'])?></td></tr><?php endforeach; ?></table><?php include '_footer.php'; ?>
